import React, { useState } from 'react';
import { Form, Button, Card, Row, Col, Badge, Alert, Spinner, Modal, ListGroup } from 'react-bootstrap';
import axios from 'axios';

function PartsSearch({ onAddToCart }) {
  const [searchTerm, setSearchTerm] = useState('');
  const [parts, setParts] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [searched, setSearched] = useState(false);
  
  // Для аналогов
  const [showAnalogues, setShowAnalogues] = useState(false);
  const [analogues, setAnalogues] = useState(null);
  const [loadingAnalogues, setLoadingAnalogues] = useState(false);

  const token = localStorage.getItem('token');

  const handleSearch = async (e) => {
    e.preventDefault();
    if (!searchTerm.trim()) return;
    setLoading(true);
    setError('');
    setSearched(true);
    try {
      const response = await axios.get(
        `http://localhost:5051/api/Parts/search?term=${encodeURIComponent(searchTerm)}`,
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setParts(response.data);
    } catch (err) {
      setError('Ошибка при поиске');
    }
    setLoading(false);
  };

  const loadAnalogues = async (partId) => {
    setLoadingAnalogues(true);
    try {
      const response = await axios.get(
        `http://localhost:5051/api/Parts/${partId}/analogues`,
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setAnalogues(response.data);
      setShowAnalogues(true);
    } catch (err) {
      setError('Ошибка загрузки аналогов');
    }
    setLoadingAnalogues(false);
  };

  const getStockBadge = (status, quantity) => {
    switch (status) {
      case 'OutOfStock': return <Badge bg="danger">Нет в наличии</Badge>;
      case 'LowStock': return <Badge bg="warning">Мало: {quantity} шт.</Badge>;
      default: return <Badge bg="success">В наличии: {quantity} шт.</Badge>;
    }
  };

  return (
    <div>
      <h2 className="mb-4">🔍 Поиск запчастей</h2>
      
      <div className="search-box">
        <Form onSubmit={handleSearch}>
          <Form.Group className="mb-3">
            <Form.Control
              size="lg"
              type="text"
              placeholder="Введите артикул, название, бренд или модель авто..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </Form.Group>
          <Button type="submit" variant="primary" size="lg" disabled={loading}>
            {loading ? <Spinner size="sm" /> : '🔍'} Поиск
          </Button>
        </Form>
      </div>

      {error && <Alert variant="danger">{error}</Alert>}
      {searched && !loading && parts.length === 0 && (
        <Alert variant="info">Ничего не найдено</Alert>
      )}

      <Row>
        {parts.map(part => (
          <Col key={part.id} md={6} lg={4} className="mb-3">
            <Card className={`part-card h-100 ${part.stockQuantity === 0 ? 'border-danger' : ''}`}>
              <Card.Body>
                <Card.Title>{part.name}</Card.Title>
                <Card.Subtitle className="mb-2 text-muted">
                  {part.brand && `${part.brand} • `}Арт: {part.articleNumber}
                </Card.Subtitle>
                
                <div className="mb-2">
                  {getStockBadge(part.stockStatus, part.stockQuantity)}
                </div>
                
                <h5 className="text-primary mb-3">{part.retailPrice.toFixed(2)} ₽</h5>
                
                <div className="d-grid gap-1">
                  <Button
                    variant={part.stockQuantity > 0 ? "success" : "secondary"}
                    disabled={part.stockQuantity === 0}
                    onClick={() => onAddToCart(part)}
                  >
                    🛒 {part.stockQuantity > 0 ? 'В корзину' : 'Нет в наличии'}
                  </Button>
                  
                  {part.stockQuantity === 0 && (
                    <Button
                      variant="outline-info"
                      size="sm"
                      onClick={() => loadAnalogues(part.id)}
                      disabled={loadingAnalogues}
                    >
                      🔄 Показать аналоги
                    </Button>
                  )}
                </div>
              </Card.Body>
            </Card>
          </Col>
        ))}
      </Row>

      {/* Модальное окно с аналогами */}
      <Modal show={showAnalogues} onHide={() => setShowAnalogues(false)} size="lg">
        <Modal.Header closeButton>
          <Modal.Title>🔄 Аналоги запчасти</Modal.Title>
        </Modal.Header>
        <Modal.Body>
          {analogues && (
            <>
              <Alert variant="warning">
                <strong>Оригинал:</strong> {analogues.originalPart.name} ({analogues.originalPart.brand}) - 
                {analogues.originalPart.retailPrice} ₽
              </Alert>
              
              <ListGroup>
                {analogues.analogues.map(a => (
                  <ListGroup.Item key={a.id} className="d-flex justify-content-between align-items-center">
                    <div>
                      <strong>{a.name}</strong>
                      <div className="text-muted">{a.brand} | Арт: {a.articleNumber}</div>
                      <Badge bg={a.stockQuantity > 0 ? 'success' : 'danger'}>
                        {a.stockQuantity > 0 ? `В наличии: ${a.stockQuantity}` : 'Нет в наличии'}
                      </Badge>
                      {a.savingsPercent > 0 && (
                        <Badge bg="info" className="ms-1">Дешевле на {a.savingsPercent}%</Badge>
                      )}
                      {a.savingsPercent < 0 && (
                        <Badge bg="warning" className="ms-1">Дороже на {Math.abs(a.savingsPercent)}%</Badge>
                      )}
                    </div>
                    <div className="text-end">
                      <h5 className="text-primary">{a.retailPrice.toFixed(2)} ₽</h5>
                      <Button
                        variant="success"
                        size="sm"
                        disabled={a.stockQuantity === 0}
                        onClick={() => {
                          onAddToCart(a);
                          setShowAnalogues(false);
                        }}
                      >
                        🛒 В корзину
                      </Button>
                    </div>
                  </ListGroup.Item>
                ))}
              </ListGroup>
            </>
          )}
        </Modal.Body>
      </Modal>
    </div>
  );
}

export default PartsSearch;
